```
function set_qtip() {
    $(".tooltip2").on("mouseover", function () {
        var $this = $(this)
        if (!$this.data("toolTipAttached")) {
            $this.qtip({
                style: {
                    widget: false,
                    classes: 'ui-tooltip-light'
                },
                content: $($(this).attr("data-tooltip")).html(),
                position: {
                    corner: {
                        target: 'topRight',
                        tooltip: 'bottomLeft'
                    }
                }
